  1→<!DOCTYPE html>
  2→<html lang="zh">
  3→<head>
  4→<meta charset="UTF-8">
  5→<title>Gate v4 最终冠军 — 657 个</title>
  6→<style>
  7→* { margin: 0; padding: 0; box-sizing: border-box; }
  8→body { font-family: -apple-system, 'SF Mono', Menlo, monospace; background: #0d1117; color: #c9d1d9; padding: 20px; }
  9→h1 { color: #58a6ff; margin-bottom: 5px; font-size: 22px; }
 10→.subtitle { color: #8b949e; margin-bottom: 20px; font-size: 13px; }
 11→.pipeline { display: flex; gap: 8px; margin-bottom: 20px; flex-wrap: wrap; }
 12→.pipeline .step { background: #161b22; border: 1px solid #30363d; border-radius: 6px; padding: 8px 12px; font-size: 12px; }
 13→.pipeline .step .num { color: #58a6ff; font-weight: bold; }
 14→.pipeline .step .cut { color: #f85149; }
 15→.filters { display: flex; gap: 10px; margin-bottom: 15px; flex-wrap: wrap; align-items: center; }
 16→.filters select, .filters input { background: #161b22; border: 1px solid #30363d; color: #c9d1d9; padding: 6px 10px; border-radius: 6px; font-size: 13px; }
 17→.filters input { width: 200px; }
 18→.filters label { color: #8b949e; font-size: 12px; }
 19→.stats { display: flex; gap: 15px; margin-bottom: 15px; }
 20→.stats .box { background: #161b22; border: 1px solid #30363d; border-radius: 6px; padding: 10px 15px; }
 21→.stats .box .val { font-size: 24px; font-weight: bold; color: #58a6ff; }
 22→.stats .box .lbl { font-size: 11px; color: #8b949e; }
 23→table { width: 100%; border-collapse: collapse; font-size: 12px; }
 24→thead { position: sticky; top: 0; z-index: 10; }
 25→th { background: #161b22; color: #58a6ff; padding: 8px 6px; text-align: left; cursor: pointer; border-bottom: 2px solid #30363d; white-space: nowrap; user-select: none; }
 26→th:hover { background: #1f2937; }
 27→th.sorted-asc::after { content: ' ▲'; }
 28→th.sorted-desc::after { content: ' ▼'; }
 29→td { padding: 6px; border-bottom: 1px solid #21262d; white-space: nowrap; }
 30→tr:hover { background: #161b22; }
 31→tr.team-short { border-left: 3px solid #f0883e; }
 32→tr.team-mid { border-left: 3px solid #58a6ff; }
 33→tr.team-long { border-left: 3px solid #3fb950; }
 34→.team-badge { display: inline-block; padding: 2px 6px; border-radius: 3px; font-size: 11px; font-weight: bold; }
 35→.team-short .team-badge { background: #f0883e22; color: #f0883e; }
 36→.team-mid .team-badge { background: #58a6ff22; color: #58a6ff; }
 37→.team-long .team-badge { background: #3fb95022; color: #3fb950; }
 38→.pos { color: #3fb950; }
 39→.neg { color: #f85149; }
 40→.dim { color: #8b949e; }
 41→.bar { display: inline-block; height: 14px; border-radius: 2px; vertical-align: middle; }
 42→.bar-green { background: #3fb950; }
 43→.bar-red { background: #f85149; }
 44→#count { color: #58a6ff; font-weight: bold; }
 45→</style>
 46→</head>
 47→<body>
 48→
 49→<h1>Gate v4 最终冠军</h1>
 50→<div class="subtitle">初考 → 专考 → 组考(正R) → 专场WF(15/15/14) → MC(100次) → OOS(80/20)</div>
 51→
 52→<div class="pipeline">
 53→  <div class="step"><span class="num">9400</span> 起跑 → 初考 <span class="cut">-921</span></div>
 54→  <div class="step"><span class="num">8479</span> → 组考(正R去重) <span class="cut">-6770</span></div>
 55→  <div class="step"><span class="num">1709</span> → WF <span class="cut">-16</span></div>
 56→  <div class="step"><span class="num">1693</span> → MC <span class="cut">-753</span></div>
 57→  <div class="step"><span class="num">940</span> → OOS <span class="cut">-283</span></div>
 58→  <div class="step"><span class="num">657</span> 🏆 最终冠军</div>
 59→</div>
 60→
 61→<div class="stats" id="stats"></div>
 62→
 63→<div class="filters">
 64→  <label>队伍:</label>
 65→  <select id="fTeam"><option value="">全部</option><option value="short">短期队</option><option value="mid">中期队</option><option value="long">长期队</option></select>
 66→  <label>币种:</label>
 67→  <select id="fCoin"><option value="">全部</option></select>
 68→  <label>策略:</label>
 69→  <input id="fStrategy" placeholder="搜索策略名...">
 70→  <label>翻倍率≥</label>
 71→  <select id="fDouble"><option value="0">不限</option><option value="50">50%</option><option value="70">70%</option><option value="90">90%</option><option value="100">100%</option></select>
 72→  <span style="color:#8b949e;font-size:12px;margin-left:10px;">显示 <span id="count">0</span> / 657</span>
 73→</div>
 74→
 75→<table>
 76→<thead>
 77→<tr>
 78→  <th data-col="idx">#</th>
 79→  <th data-col="team">队伍</th>
 80→  <th data-col="strategy">策略</th>
 81→  <th data-col="coin">币种</th>
 82→  <th data-col="interval">周期</th>
 83→  <th data-col="all_pnl">总PnL(R)</th>
 84→  <th data-col="oos_pnl">OOS PnL</th>
 85→  <th data-col="oos_wr">OOS胜率</th>
 86→  <th data-col="double_rate">翻倍率</th>
 87→  <th data-col="d2d">d2d范围</th>
 88→  <th data-col="max_dd">maxDD范围</th>
 89→  <th data-col="trades">笔数</th>
 90→</tr>
 91→</thead>
 92→<tbody id="tbody"></tbody>
 93→</table>
 94→
 95→<script>
 96→const DATA = [];
 97→</script>
 98→
 99→</body>
100→</html>
